import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { Gamepad2, Users, Trophy, Send, Check } from 'lucide-react';

const GameRoom = () => {
  const { gameId } = useParams();
  const [isReady, setIsReady] = useState(false);
  const [players, setPlayers] = useState([
    { id: 1, name: 'Player1', isReady: true },
    { id: 2, name: 'Player2', isReady: false },
    { id: 3, name: 'rupesh123', isReady: false, isCurrentPlayer: true }
  ]);
  const [allPlayersReady, setAllPlayersReady] = useState(false);

  useEffect(() => {
    const allReady = players.every(player => player.isReady);
    setAllPlayersReady(allReady);
  }, [players]);

  return (
    <div className="min-h-screen p-4 md:p-6">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-white mb-2">Game Room</h1>
          <p className="text-gray-400">Game ID: {gameId}</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          {/* Game Board */}
          <div className="lg:col-span-3">
            <div className="card p-8">
              <div className="aspect-square bg-gradient-to-br from-gray-800 to-gray-900 rounded-xl flex items-center justify-center">
                <div className="text-center">
                  <Gamepad2 className="h-16 w-16 text-accent-400 mx-auto mb-4" />
                  <h2 className="text-xl font-semibold text-white mb-2">Game Board</h2>
                  <p className="text-gray-400">Game will start when all players are ready</p>
                </div>
              </div>
            </div>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Players */}
            <div className="card">
              <h3 className="text-lg font-semibold text-white mb-4">Players</h3>
              <div className="space-y-3">
                {[1, 2, 3].map((player) => (
                  <div key={player} className="flex items-center space-x-3">
                    <div className="w-8 h-8 bg-gradient-to-r from-accent-400 to-accent-600 rounded-full"></div>
                    <div className="flex-1">
                      <p className="text-white text-sm">Player {player}</p>
                      <p className="text-gray-500 text-xs">Ready</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Chat */}
            <div className="card">
              <h3 className="text-lg font-semibold text-white mb-4">Chat</h3>
              <div className="space-y-3 mb-4">
                <div className="text-sm">
                  <span className="text-accent-400">Player1:</span>
                  <span className="text-gray-400 ml-2">Good luck!</span>
                </div>
              </div>
              <div className="flex space-x-2">
                <input
                  type="text"
                  placeholder="Type message..."
                  className="input text-sm flex-1"
                />
                <button className="btn-primary p-2">
                  <Send className="h-4 w-4" />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GameRoom;
